use std::fs;

fn main() {
    let poly_dir = "tests/fixtures/payloads/polyglot";
    fs::create_dir_all(poly_dir).ok();

    let assets = [
        ("java", "package com.transmutation.core;\nimport java.util.*;\n\npublic class DocumentProcessor {\n    private final String processorId;\n    \n    public DocumentProcessor(String id) {\n        this.processorId = id;\n    }\n\n    @Override\n    public Result process(byte[] inputData) throws ProcessingException {\n        if (inputData == null) throw new ProcessingException(\"Empty data\");\n        System.out.println(\"Processing in Java: \" + processorId);\n        return new Result(true, \"Success\");\n    }\n}"),
        ("cs", "using System;\nusing System.Threading.Tasks;\n\nnamespace Transmutation.Services {\n    public interface IProcessor {\n        Task<bool> RunAsync(string path);\n    }\n\n    public class LinuxProcessor : IProcessor {\n        [LogAttribute]\n        public async Task<bool> RunAsync(string path) {\n            Console.WriteLine($\"Running C# on {path}\");\n            await Task.Delay(10);\n            return true;\n        }\n    }\n}"),
        ("cpp", "#include <iostream>\n#include <vector>\n#include <memory>\n\nnamespace core {\n    class NativeEngine {\n    public:\n        NativeEngine(int threads) : m_threads(threads) {}\n        virtual ~NativeEngine() = default;\n        \n        void execute(const std::vector<char>& buffer) {\n            if (buffer.empty()) return;\n            std::cout << \"Executing C++ Native\" << std::endl;\n        }\n    private:\n        int m_threads;\n    };\n}"),
        ("php", "<?php\nnamespace Transmutation\\Drivers;\n\nuse Exception;\n\nclass FileDriver {\n    private $config;\n\n    public function __construct(array $config) {\n        $this->config = $config;\n    }\n\n    /**\n     * @param string $path\n     * @return bool\n     */\n    public function validate(string $path): bool {\n        if (!file_exists($path)) {\n            throw new Exception(\"File not found: \" . $path);\n        }\n        return true;\n    }\n}"),
        ("ruby", "module Transmutation\n  class RubyWorker\n    attr_reader :worker_id\n\n    def initialize(id)\n      @worker_id = id\n    end\n\n    def transform(payload)\n      return nil if payload.nil?\n      puts \"Transforming in Ruby: #{@worker_id}\"\n      payload.upcase\n    rescue => e\n      log_error(e)\n    end\n\n    private\n    def log_error(err)\n      warn \"Error: #{err.message}\"\n    end\n  end\nend"),
        ("swift", "import Foundation\n\nprotocol LogicDelegate {\n    func didCompleteTransform(result: String)\n}\n\nclass SwiftEngine: ObservableObject {\n    @Published var status: String = \"idle\"\n    var delegate: LogicDelegate?\n\n    func perform(input: Data) -> Result<String, Error> {\n        self.status = \"running\"\n        let id = UUID().uuidString\n        print(\"Swift ID: \\(id)\")\n        return .success(\"Transformed\")\n    }\n}"),
        ("kotlin", "package org.transmutation.ml\n\nimport java.io.File\n\nclass ModelLoader {\n    @JvmStatic\n    fun loadWeights(path: String): Map<String, Float> {\n        val file = File(path)\n        if (!file.exists()) return emptyMap()\n        println(\"Kotlin loading: $path\")\n        return mapOf(\"weight_1\" to 0.5f)\n    }\n}"),
        ("scala", "package transmutation.fp\n\ntrait Transformable[T] {\n    def transform(item: T): T\n}\n\nobject GlobalProcessor extends App {\n    def run[T](input: List[T])(implicit t: Transformable[T]): List[T] = {\n        input.map(t.transform)\n    }\n}"),
        ("dart", "import 'package:transmutation/api.dart';\n\nclass UiController extends BaseController {\n    final String title;\n    UiController({required this.title});\n\n    @override\n    void onInit() {\n        print('Dart initialized: $title');\n        super.onInit();\n    }\n}"),
        ("zig", "const std = @import(\"std\");\n\npub const Engine = struct {\n    allocator: std.mem.Allocator,\n\n    pub fn init(alloc: std.mem.Allocator) Engine {\n        return Engine{ .allocator = alloc };\n    }\n\n    pub fn process(self: *Engine, data: []const u8) !void {\n        const stdout = std.io.getStdOut().writer();\n        try stdout.print(\"Zig processed: {s}\\n\", .{data});\n    }\n};"),
        ("mojo", "fn process_data(data: SIMD[f32, 8]):\n    let threshold: Float32 = 0.5\n    if data[0] > threshold:\n        print(\"Mojo high signal\")\n    else:\n        print(\"Mojo low signal\")"),
        ("haskell", "module DataTransformer where\n\ndata TransformResult = Success String | Failure String\n\napplyTransformation :: String -> TransformResult\napplyTransformation input\n    | length input > 10 = Success (reverse input)\n    | otherwise = Failure \"Input too short\"\n\nmain :: IO ()\nmain = putStrLn \"Haskell Engine Ready\""),
        ("erlang", "-module(transmute_srv).\n-behaviour(gen_server).\n-export([start_link/0, init/1, handle_call/3]).\n\ninit(Args) ->\n    {ok, Args}.\n\nhandle_call({transform, Data}, _From, State) ->\n    Reply = binary_to_list(Data),\n    {reply, Reply, State}."),
        ("elixir", "defmodule Transmutation.Worker do\n  use GenServer\n  @doc \"Initializes the worker\"\n  def start_link(opts \\\\ []) do\n    GenServer.start_link(__MODULE__, :ok, opts)\n  end\n\n  def handle_cast({:process, data}, state) do\n    IO.inspect(data, label: \"Elixir Process\")\n    {:noreply, state}\n  end\nend"),
        ("rust", "pub trait DocumentConverter {\n    fn convert(&self, path: &Path) -> Result<String, Error>;\n}\n\npub struct PdfConverter {\n    config: Config,\n}\n\nimpl DocumentConverter for PdfConverter {\n    fn convert(&self, path: &Path) -> Result<String, Error> {\n        tracing::info!(\"Rust converting: {:?}\", path);\n        Ok(\"content\".to_string())\n    }\n}"),
        ("ts", "import { Injectable, Logger } from '@nestjs/common';\n\n@Injectable()\nexport class TokenSqueezer {\n    private readonly logger = new Logger(TokenSqueezer.name);\n\n    async squeeze(tokens: string[]): Promise<number> {\n        this.logger.debug(`Squeezing ${tokens.length} tokens`);\n        return tokens.length * 0.5;\n    }\n}"),
        ("py", "import logging\nfrom typing import List\n\nclass SemanticEngine:\n    def __init__(self, model_name: str):\n        self.logger = logging.getLogger(__name__)\n        self.model = model_name\n\n    def predict(self, inputs: List[float]) -> bool:\n        self.logger.info(f\"Python predicting with {self.model}\")\n        return sum(inputs) > 0.5"),
        ("c", "#include <stdlib.h>\n#include <string.h>\n\ntypedef struct {\n    int status_code;\n    char* message;\n} ApiResponse;\n\nApiResponse* create_response(int code, const char* msg) {\n    ApiResponse* res = malloc(sizeof(ApiResponse));\n    res->status_code = code;\n    res->message = strdup(msg);\n    return res;\n}"),
        ("go", "package context\n\nimport \"fmt\"\n\ntype ContextManager struct {\n    SessionID string\n}\n\nfunc (cm *ContextManager) Authenticate(token string) (bool, error) {\n    fmt.Printf(\"Go Auth: %s\\n\", cm.SessionID)\n    if token == \"\" { return false, fmt.Errorf(\"invalid\") }\n    return true, nil\n}"),
        ("sql", "BEGIN;\nCREATE TABLE IF NOT EXISTS audit_logs (\n    request_id UUID PRIMARY KEY,\n    user_email TEXT NOT NULL,\n    action_type VARCHAR(50) CHECK (action_type IN ('CREATE', 'UPDATE', 'DELETE')),\n    metadata JSONB,\n    created_at TIMESTAMPTZ DEFAULT NOW()\n);\nCOMMIT;"),
    ];

    for (ext, content) in assets {
        let path = format!("{}/sample.{}", poly_dir, ext);
        fs::write(path, content).unwrap();
    }
    println!("Generated 20 REALISTIC Polyglot Assets in {}", poly_dir);
}
